const Services = () => {
  // const dummyServices = [
  //   { service_name: "Cash Withdrawal", slug: "CW", status: true },
  //   { service_name: "Balance Enquiry", slug: "BE", status: true },
  //   { service_name: "Mini Statement", slug: "MS", status: false },
  // ];

  const { service } = useParams();

  const [allServices, setAllServices] = useState([]);

  const { selectedAEPSProvider } = useAEPSService();

  const getAllServices = async () => {
    try {
      let res = await getAepsservies(selectedAEPSProvider);
      if (res?.data?.statusCode === 200) {
        setAllServices(res?.data?.data || []);
      } else {
        setAllServices([]);
      }
    } catch (error) {}
  };

  const getCashDeposite = async () => {
    try {
      let res = await getAepsCashDeposite(selectedAEPSProvider);
      if (res?.data?.statusCode === 200) {
        setAllServices(res?.data?.data || []);
      } else {
        setAllServices([]);
      }
    } catch (error) {}
  };
  useEffect(() => {
    if (!service) {
      getAllServices();
    }

    if (service === "cash-deposit") {
      getCashDeposite();
    }
  }, [selectedAEPSProvider]);

  const serviceComponentMap = {
    CW: CashWithdrawalWithPin,
    BE: BalanceEnquiryWithPin,
    MS: MiniStatementWithPin,
    CD: CashDepositeWithPin,
    // aadhaar_pay: AadhaarPay,
  };

  const [selectedService, setSelectedService] = useState(null);

  const handleServiceClick = (service) => {
    if (!service.status) {
      toast.error(`${service.service_name} is not active.`);
      return;
    }
    setSelectedService(service.slug);
  };

  const SelectedComponent = selectedService
    ? serviceComponentMap[selectedService]
    : null;

  const cardSx = {
    borderRadius: "20px",
    background: "var(--bs-primary3)",
    boxShadow: "0 6px 20px rgba(0,0,0,0.06)",
    transition: "0.25s",
  };

  return (
    <CustomBox>
      <Box p={2}>
        {!selectedService ? (
          <>
            <Typography
              variant="h6"
              mb={2}
              color="var(--bs-primary2)"
              sx={{
                textAlign: "center",
              }}
            >
              AEPS Services
            </Typography>

            <Grid container spacing={2}>
              {allServices?.map((service) => (
                <Grid item xs={12} sm={6} md={3} key={service.slug}>
                  <Card
                    sx={{
                      ...cardSx,
                      opacity: service.status ? 1 : 0.5,
                      border: service.status
                        ? "1px solid #e0e6ef"
                        : "1px dashed #cfd6df",
                    }}
                  >
                    <CardActionArea onClick={() => handleServiceClick(service)}>
                      <CardContent sx={{ textAlign: "center", py: 3 }}>
                        <Typography
                          variant="subtitle1"
                          fontWeight="bold"
                          color="var(--bs-primary2)"
                          component={"span"}
                        >
                          {service.service_name}
                        </Typography>
                        {!service.status && (
                          <Typography
                            fontSize={10}
                            sx={{ ml: 1 }}
                            component={"span"}
                            color="error"
                          >
                            Not Active
                          </Typography>
                        )}
                      </CardContent>
                    </CardActionArea>
                  </Card>
                </Grid>
              ))}
            </Grid>
          </>
        ) : (
          <>
            <Box display="flex" alignItems="center" gap={1} mb={2}>
              <IconButton onClick={() => setSelectedService(null)}>
                <ArrowBackIosNewIcon />
              </IconButton>
              <Typography variant="h6" color="var(--bs-primary2)">
                {allServices
                  ?.find((item) => item?.slug === selectedService)
                  ?.service_name.replace(/_/g, " ")
                  .toUpperCase()}
              </Typography>
            </Box>
            {SelectedComponent && <SelectedComponent />}
          </>
        )}
      </Box>
    </CustomBox>
  );
};

const AEPSOnboarding = ({ ensureLocation }) => {
  const [open, setOpen] = useState(false);
  const [otp, setOtp] = useState("");
  const {
    setAepsGlobalLoader,
    setAepsCurrentPage,
    selectedAEPSProvider,
    setTriggerAuthApi,
  } = useAEPSService();

  const handleOpen = () => setOpen(true);
  const handleClose = () => {
    setOpen(false);
    setOtp("");
  };

  const otpSend = async () => {
    const { latitude, longitude } = await ensureLocation();

    setAepsGlobalLoader(true);
    let body = {
      bank: selectedAEPSProvider,
      latitude: latitude,
      longitude: longitude,
    };
    try {
      let res = await getAepsOnboarding(body);
      if (res?.data?.statusCode === "007") {
        handleOpen();
      }
      toastMessage(res?.data?.error, res?.data?.message);
    } catch (error) {
    } finally {
      setAepsGlobalLoader(false);
    }
  };

  const handleVerify = async () => {
    setAepsGlobalLoader(true);
    const clone = {
      mobile: window.localStorage.getItem("regisNumber").slice(-10),
      otp: otp,
    };
    try {
      const res = await verifybank3otp(clone);
      if (res?.data?.statusCode === 200) {
        setAepsCurrentPage("");
        setTriggerAuthApi((pre) => !pre);
        // setCurrentPage('money-transfer')
        // handleClose();
      }
      toastMessage(res?.data?.error, res?.data?.message);
    } catch (error) {
    } finally {
      setAepsGlobalLoader(false);
    }
  };

  return (
    <>
      <CustomBox>
        <Box display="flex" alignItems="center" gap={2} mb={2}>
          <Typography
            variant="body2"
            color="var(--bs-primary2)"
            fontWeight="bold"
            fontSize={18}
          >
            Service
          </Typography>
        </Box>
        <Typography
          variant="body2"
          color="var(--bs-primary2)"
          fontWeight="bold"
          fontSize={16}
        >
          Please complete your onboarding process by{" "}
          <Typography
            component={"span"}
            sx={{ cursor: "pointer", textDecoration: "underline" }}
            onClick={otpSend}
          >
            clicking here{" "}
          </Typography>
        </Typography>
      </CustomBox>

      <Dialog open={open} onClose={handleClose} maxWidth="xs" fullWidth>
        <DialogTitle sx={{ color: "var(--bs-primary2)" }}>
          OTP Verification
        </DialogTitle>
        <DialogContent>
          <Typography mb={2} sx={{ color: "var(--bs-primary2)" }}>
            Enter the 6-digit code sent to your mobile number.
          </Typography>

          <CustomTextField
            fullWidth
            label="Enter OTP"
            value={otp}
            onChange={(e) => {
              const onlyDigits = e.target.value.replace(/\D/g, "");
              if (onlyDigits.length <= 6) setOtp(onlyDigits);
            }}
            inputProps={{ maxLength: 6 }}
            autoFocus
          />
        </DialogContent>

        <DialogActions>
          <Button onClick={handleClose}>Cancel</Button>
          <Button
            onClick={handleVerify}
            sx={{
              borderColor: "var(--bs-primary1)",
              backgroundColor: "var(--bs-primary1)",
              color: "var(--bs-primary2)",
            }}
            variant="contained"
            disabled={otp.length < 6}
          >
            Verify
          </Button>
        </DialogActions>
      </Dialog>
    </>
  );
};

const AEPSOnboardingWithPin = withPinLocation(AEPSOnboarding);
const CheckDailyAuthWithPin = withPinLocation(CheckDailyAuth);

const AEPSPage = () => {
  const {
    aepsglobalLoader,
    setAepsGlobalLoader,
    aepscurrentPage,
    dailyAuth,
    onBoardingAuth,
    setAepsCurrentPage,
  } = useAEPSService();

  return (
    <Box sx={{ position: "relative", isolation: "isolate", minHeight: "100vh" }}>
      <AepsBackground />
      {aepsglobalLoader && <Loader />}
      <BankSelection />
      {aepscurrentPage === "onboarding-Page" && <AEPSOnboardingWithPin />}
      {aepscurrentPage === "daily-Auth" && <CheckDailyAuthWithPin />}
      {aepscurrentPage === "services" && <Services />}
    </Box>
  );
};

export default AEPSPage;
